+function drawTiledWall(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
+  const wc: Record<CharacterType, [string, string, string]> = {
+    king: ['#3e3650', '#484060', '#353048'], nobility: ['#3a3850', '#44405a', '#323048'],
+    knight: ['#384050', '#404858', '#303848'], squire: ['#384038', '#404840', '#303830'],
+    healer: ['#303850', '#384058', '#282e48'], sentinel: ['#303848', '#3a4050', '#282e40'],
+    scribe: ['#3a3430', '#443c38', '#322c28'], judge: ['#383040', '#403848', '#302838'],
+    blacksmith: ['#383028', '#403830', '#302820'],
+  };
+  const [base, light, dark] = wc[type];
+  ctx.fillStyle = base; ctx.fillRect(x, y, w, h);
+  const bW = 20, bH = 10, seed = x * 7 + y * 13;
+
+  // Draw individual bricks with mortar lines, depth shading, and moss/damage details
+  for (let row = 0; row < Math.ceil(h / bH); row++) {
+    const off = row % 2 === 0 ? 0 : bW * 0.5;
+    for (let col = -1; col < Math.ceil(w / bW) + 1; col++) {
+      const bx = x + col * bW + off, by = y + row * bH;
+      if (bx + bW < x || bx > x + w) continue;
+
+      // Base brick color variation for depth
+      const hash = ((bx * 31 + by * 17 + seed) & 0xFF) / 255;
+      let brickColor = base;
+      if (hash > 0.7) brickColor = light;
+      else if (hash < 0.3) brickColor = dark;
+
+      // Draw brick base
+      ctx.fillStyle = brickColor;
+      ctx.fillRect(bx + 1, by + 1, bW - 2, bH - 2);
+
+      // Mortar lines (top and left edges)
+      ctx.fillStyle = 'rgba(200, 200, 200, 0.15)';
+      ctx.fillRect(bx, by, bW, 2);
+      ctx.fillRect(bx, by, 2, bH);
+
+      // Depth shading: shadow bottom and right edges
+      ctx.fillStyle = 'rgba(0, 0, 0, 0.15)';
+      ctx.fillRect(bx + 1, by + bH - 2, bW - 2, 2);
+      ctx.fillRect(bx + bW - 2, by + 1, 2, bH - 2);
+
+      // Subtle highlights on top-left edges for 3D effect
+      ctx.fillStyle = 'rgba(255, 255, 255, 0.1)';
+      ctx.fillRect(bx + 1, by + 1, bW - 3, 1);
+      ctx.fillRect(bx + 1, by + 1, 1, bH - 3);
+
+      // Moss or damage details: small random green or dark spots
+      const mossChance = ((bx * 13 + by * 7 + seed) & 0xFF) / 255;
+      if (mossChance > 0.85) {
+        ctx.fillStyle = 'rgba(50, 80, 30, 0.3)';
+        ctx.fillRect(bx + 3, by + 3, 4, 2);
+        ctx.fillRect(bx + 10, by + 5, 3, 2);
+      } else if (mossChance < 0.1) {
+        ctx.fillStyle = 'rgba(30, 20, 20, 0.2)';
+        ctx.fillRect(bx + 6, by + 2, 2, 3);
+        ctx.fillRect(bx + 12, by + 6, 3, 2);
+      }
+    }
+  }
+
+  // Subtle top highlight overlay for wall top edge
+  ctx.fillStyle = 'rgba(255,255,255,0.06)';
+  ctx.fillRect(x, y, w, 2);
+}
